import React, { useEffect, useState } from 'react';

const CLIENT_ID = 'YOUR_CLIENT_ID';
const REDIRECT_URI = 'YOUR_REDIRECT_URI';
const AUTH_URL = 'https://authorization-server.com/auth';
const TOKEN_URL = 'https://authorization-server.com/token';
const SCOPE = 'YOUR_SCOPES';

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const code = params.get('code');

    if (code) {
      exchangeCodeForToken(code);
    }
  }, []);

  const handleLogin = () => {
    const authUrl = `${AUTH_URL}?response_type=code&client_id=${CLIENT_ID}&redirect_uri=${REDIRECT_URI}&scope=${SCOPE}`;
    window.location.href = authUrl;
  };

  const exchangeCodeForToken = async (code) => {
    try {
      const response = await fetch(TOKEN_URL, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          code: code,
          redirect_uri: REDIRECT_URI,
          client_id: CLIENT_ID,
        }),
      });

      if (!response.ok) throw new Error('Token exchange failed');

      const data = await response.json();
      localStorage.setItem('access_token', data.access_token);
      setIsAuthenticated(true);
    } catch (error) {
      console.error('Error exchanging code for token:', error);
    }
  };

  const fetchProtectedResource = async () => {
    const token = localStorage.getItem('access_token');
    if (!token) return;

    try {
      const response = await fetch('https://api.yourservice.com/protected', {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      if (!response.ok) throw new Error('Failed to fetch protected resource');

      const data = await response.json();
      console.log('Protected data:', data);
    } catch (error) {
      console.error('Error fetching protected resource:', error);
    }
  };

  return (
    <div>
      <h1>OAuth 2.0 SPA</h1>
      {isAuthenticated ? (
        <div>
          <h2>Welcome!</h2>
          <button onClick={fetchProtectedResource}>Fetch Protected Resource</button>
        </div>
      ) : (
        <button onClick={handleLogin}>Login with OAuth</button>
      )}
    </div>
  );
};

export default App;